-- =============================================================================
-- import_inventaire_ia92.sql — Bâti patrimonial « Inventaire général » (Mérimée/POP)
-- =============================================================================
-- PÉRIMÈTRE : Inventaire général du dép. 92 uniquement (REF commençant par IA92).
--             NE touche PAS monuments_historiques (table MH scellée), ni le moteur
--             de score, ni le golden.
-- USAGE     : DESCRIPTIF uniquement. inventaire_general n'alimente JAMAIS le verdict
--             binaire Sans Vis-à-Vis® ni le score de qualité de vue. Sert au badge
--             « bâti patrimonial » (affichage), désactivable via badge_actif /
--             deno_affichage (aujourd'hui liste blanche totale, table vide).
-- TOLÉRANCE : rattachement point→bâti = ST_Contains sinon KNN <-> ≤ 15 m.
--             Tolérance 15 m VERROUILLÉE (miroir du rattachement MH). Ne pas dévier.
-- CHAÎNE (ordre figé, ne pas réordonner) :
--   1. adresse : voie (trigram, bonne commune) + n° exact sinon voisin ±2
--                (bis/ter→nu ; multi-adresses éclatées) → point → ST_Contains
--                sinon KNN ≤15 m           → mode num_exact / voisin_2
--   2. CADA → parcelle (bonne commune INSEE) → bâtis (ST_PointOnSurface inclus) :
--        - 1 bâti           → cada_1bati
--        - >1 bâti          → PLUS GRANDE EMPRISE ST_Area ; égalité stricte du
--                             max → TOUS les ex æquo (1 ligne/cleabs) →
--                             cada_max_emprise ; écart max/2e <15 % → desamb_serree
--        - 0 bâti           → non rattaché
--   3. bonus : point POP (POP_COORDONNEES) dans parcelle, même règle 1 bâti /
--              emprise max → point_parcelle
--   4. sinon : non rattaché (cleabs NULL, traçabilité). JAMAIS de centroïde de voie.
--
-- REPLAY Paris + petite couronne : régénérer les candidats (VALUES ci-dessous) à
--   partir de l'export POP correspondant en changeant le filtre de référence
--   IA75 / IA92 / IA93 / IA94 (même parseur XLSX + mêmes règles DENO/DOSS).
--   Le corps SQL (norm_voie, résolution, INSERT) est identique quel que soit le dépt.
--
-- PROVENANCE DES DONNÉES : les blocs VALUES (t_notice / t_adr / t_cada / t_pt) sont
--   générés hors-ligne par le parseur Python de l'export XLSX POP (search/advanced
--   + notice-export/sync/public), qui applique le filtre « bâti » (seau BÂTI = 306 ;
--   exclut ESPACE_VERT, COLLECTIF/ÉTUDE, MONUMENT/FUNÉRAIRE via DENO+DOSS), dérive
--   commune_insee (WEB=INSEE sinon LOCA après "(92)") et parse ADRS / CADA.
--   Re-jouer ce fichier tel quel reproduit à l'identique l'import IA92.
--   NB : sur base déjà importée, DROP TABLE inventaire_general au préalable.
-- =============================================================================

-- 1) Extensions (idempotent) --------------------------------------------------
CREATE EXTENSION IF NOT EXISTS unaccent;
CREATE EXTENSION IF NOT EXISTS pg_trgm;

-- 2) Normaliseur de voie (unaccent → lower → ponctuation en espaces → abréviations)
CREATE OR REPLACE FUNCTION norm_voie(s text) RETURNS text AS $$
  SELECT btrim(regexp_replace(
    regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(
    regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(
      regexp_replace(lower(unaccent(coalesce(s,''))),'[^a-z0-9]+',' ','g'),
      '\yave?\y','avenue'), '\ybd\y','boulevard'), '\ybld\y','boulevard'),
      '\yboul\y','boulevard'), '\ypl\y','place'), '\yimp\y','impasse'),
      '\yst\y','saint'), '\yste\y','sainte'), '\ydr\y','docteur'),
      '\ygal\y','general'), '\ymal\y','marechal'), '\yrte\y','route'),
    '\s+',' ','g'))
$$ LANGUAGE sql IMMUTABLE;

-- 3) Tables -------------------------------------------------------------------
CREATE TABLE inventaire_general (
  id            bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  ref           text NOT NULL,
  deno text, nom text, commune_insee text, datation text,
  adresse text, cada_ref text,
  statut        text NOT NULL DEFAULT 'bati_patrimonial',
  cleabs        text,                 -- NULL = non rattaché
  mode_rattachement text,             -- num_exact|voisin_2|cada_1bati|cada_max_emprise|point_parcelle
  dist_m        numeric,
  desamb_serree boolean NOT NULL DEFAULT false,
  badge_actif   boolean NOT NULL DEFAULT true,
  geom_point    geometry(Point,2154),
  UNIQUE (ref, cleabs)
);
CREATE INDEX ON inventaire_general (cleabs);
CREATE TABLE IF NOT EXISTS deno_affichage (deno text PRIMARY KEY, affichable boolean NOT NULL);
-- deno_affichage reste VIDE : aujourd'hui liste blanche totale (toutes catégories affichées).

-- 4) Ingestion + chaîne de rattachement (une transaction) ---------------------
BEGIN;
CREATE TEMP TABLE t_notice(ref text,deno text,nom text,commune_insee text,datation text,adresse text,cada_ref text,lat float8,lon float8) ON COMMIT DROP;
