CREATE TEMP TABLE tmp_ban92 ON COMMIT DROP AS
  SELECT fid,numero,nom_voie,insee_commune,norm_voie(nom_voie) AS voie_norm,geom
  FROM adresse_ban WHERE insee_commune LIKE '92%';
CREATE INDEX ON tmp_ban92 USING gin(voie_norm gin_trgm_ops);
CREATE INDEX ON tmp_ban92(insee_commune,nom_voie,numero);
ANALYZE tmp_ban92;

INSERT INTO inventaire_general (ref,deno,nom,commune_insee,datation,adresse,cada_ref,cleabs,mode_rattachement,dist_m,desamb_serree,geom_point)
WITH
adr_geo AS (
  SELECT c.ref,c.ord,c.num,c.voie,c.insee, v.voie AS voie_match, p.geom, (p.numero=c.num) AS exact
  FROM t_adr c
  LEFT JOIN LATERAL (
    SELECT b.nom_voie AS voie
    FROM tmp_ban92 b
    WHERE c.insee IS NOT NULL AND b.insee_commune=c.insee
      AND b.voie_norm % norm_voie(c.voie)
    GROUP BY b.nom_voie
    ORDER BY max(similarity(b.voie_norm, norm_voie(c.voie))) DESC
    LIMIT 1
  ) v ON true
  LEFT JOIN LATERAL (
    SELECT b.geom, b.numero
    FROM tmp_ban92 b
    WHERE b.insee_commune=c.insee AND b.nom_voie=v.voie
      AND c.num IS NOT NULL AND b.numero BETWEEN c.num-2 AND c.num+2
    ORDER BY abs(b.numero-c.num) ASC, (b.numero=c.num) DESC
    LIMIT 1
  ) p ON true
),
adr_best AS (SELECT DISTINCT ON (ref) * FROM adr_geo ORDER BY ref,(geom IS NOT NULL) DESC, ord),
adr_res AS (
  SELECT ref,
         COALESCE(
           (SELECT b.cleabs FROM batiment b WHERE ST_Contains(b.geom,ab.geom) LIMIT 1),
           (SELECT b.cleabs FROM batiment b WHERE ST_DWithin(b.geom,ab.geom,15) ORDER BY b.geom<->ab.geom LIMIT 1)
         ) AS cleabs,
         (SELECT round(ST_Distance(b.geom,ab.geom)::numeric,2) FROM batiment b WHERE ST_DWithin(b.geom,ab.geom,15) ORDER BY b.geom<->ab.geom LIMIT 1) AS dist,
         CASE WHEN ab.exact THEN 'num_exact' ELSE 'voisin_2' END AS mode,
         ab.geom AS geom_point
  FROM adr_best ab WHERE ab.geom IS NOT NULL
),
adr_final AS (SELECT ref,cleabs,dist,mode,geom_point FROM adr_res WHERE cleabs IS NOT NULL),
cada_par AS (
  SELECT c.ref,c.ord,pc.id AS pid,pc.geom AS pgeom,
    (SELECT count(*) FROM batiment b WHERE ST_Intersects(b.geom,pc.geom) AND ST_Contains(pc.geom,ST_PointOnSurface(b.geom))) AS nbat
  FROM t_cada c
  JOIN parcelle pc ON pc.commune=c.insee AND pc.section=c.section
    AND c.numero IS NOT NULL AND pc.numero ~ '^[0-9]+$' AND pc.numero::int=c.numero::int
),
cada_best AS (SELECT DISTINCT ON (ref) * FROM cada_par ORDER BY ref,(nbat=1) DESC,(nbat>0) DESC, ord),
cada_bats AS (
  SELECT cb.ref, cb.nbat, b.cleabs, ST_Area(b.geom) AS area,
         max(ST_Area(b.geom)) OVER (PARTITION BY cb.ref) AS maxarea
  FROM cada_best cb
  JOIN batiment b ON ST_Intersects(b.geom,cb.pgeom) AND ST_Contains(cb.pgeom,ST_PointOnSurface(b.geom))
  WHERE cb.nbat>0
),
cada_second AS (SELECT ref, max(area) AS second FROM cada_bats WHERE area<maxarea GROUP BY ref),
cada_res AS (
  SELECT cb.ref, cb.cleabs,
    CASE WHEN cb.nbat=1 THEN 'cada_1bati' ELSE 'cada_max_emprise' END AS mode,
    (cb.nbat>1 AND cs.second IS NOT NULL AND (cb.maxarea-cs.second)/cb.maxarea < 0.15) AS desamb
  FROM cada_bats cb LEFT JOIN cada_second cs USING(ref)
  WHERE cb.area = cb.maxarea
),
pt_par AS (
  SELECT c.ref, c.g AS geom_point, pc.geom AS pgeom
  FROM (SELECT ref, ST_Transform(ST_SetSRID(ST_MakePoint(lon,lat),4326),2154) AS g FROM t_pt) c
  JOIN parcelle pc ON ST_Contains(pc.geom, c.g)
),
pt_bats AS (
  SELECT pp.ref, pp.geom_point, b.cleabs, ST_Area(b.geom) AS area,
         max(ST_Area(b.geom)) OVER (PARTITION BY pp.ref) AS maxarea
  FROM pt_par pp JOIN batiment b ON ST_Intersects(b.geom,pp.pgeom) AND ST_Contains(pp.pgeom,ST_PointOnSurface(b.geom))
),
pt_res AS (SELECT ref,cleabs,geom_point FROM pt_bats WHERE area=maxarea),
final AS (
  SELECT ref,cleabs,dist::numeric AS dist_m,mode,false AS desamb,geom_point::geometry AS geom_point FROM adr_final
  UNION ALL
  SELECT ref,cleabs,NULL::numeric,mode,desamb,NULL::geometry FROM cada_res
    WHERE ref NOT IN (SELECT ref FROM adr_final)
  UNION ALL
  SELECT ref,cleabs,NULL::numeric,'point_parcelle',false,geom_point::geometry FROM pt_res
    WHERE ref NOT IN (SELECT ref FROM adr_final) AND ref NOT IN (SELECT ref FROM cada_res)
  UNION ALL
  SELECT ref,NULL::text,NULL::numeric,NULL::text,false,NULL::geometry FROM t_notice
    WHERE ref NOT IN (SELECT ref FROM adr_final)
      AND ref NOT IN (SELECT ref FROM cada_res)
      AND ref NOT IN (SELECT ref FROM pt_res)
)
SELECT f.ref,n.deno,n.nom,n.commune_insee,n.datation,n.adresse,n.cada_ref,
       f.cleabs,f.mode,f.dist_m,f.desamb,f.geom_point
FROM final f JOIN t_notice n USING(ref);

COMMIT;

-- 5) Vérifications (lecture seule ; ne modifient rien) -------------------------
-- V1 — rattachement global (attendu ~ 250 / 306 / 250) :
--   notices rattachées / notices totales / cleabs badgés
SELECT count(DISTINCT ref) FILTER (WHERE cleabs IS NOT NULL) AS notices_rattachees,
       count(DISTINCT ref)                                    AS notices_total,
       count(*) FILTER (WHERE cleabs IS NOT NULL)             AS cleabs_badges
FROM inventaire_general;

-- V2 — cas de désambiguïsation serrée (écart emprise max/2e < 15 % ; attendu 2) :
SELECT count(*) FROM inventaire_general WHERE desamb_serree;

-- V3 — répartition des modes de rattachement :
--   attendu ~ num_exact 203, voisin_2 18, cada_max_emprise 16, cada_1bati 10,
--            point_parcelle 3, (NULL) 56
SELECT mode_rattachement, count(*) FROM inventaire_general GROUP BY 1 ORDER BY 2 DESC;

-- V4 — GOLDEN : monuments_historiques doit rester INCHANGÉE
--   (count = 176, md5 = 287a726cde813fc2e9fd74c5f6c6c10c au moment de l'import) :
SELECT count(*) AS mh_count,
       md5(string_agg(ref||coalesce(cleabs,'')||statut,',' ORDER BY ref)) AS mh_md5
FROM monuments_historiques;

-- V5a — 5 lignes rattachées :
SELECT ref, left(deno,26) AS deno, cleabs, mode_rattachement, dist_m, desamb_serree
FROM inventaire_general WHERE cleabs IS NOT NULL
ORDER BY mode_rattachement, ref LIMIT 5;

-- V5b — 3 lignes non rattachées (cleabs NULL ; badge_actif=true mais ne badge pas) :
SELECT ref, left(deno,24) AS deno, left(adresse,26) AS adresse,
       left(cada_ref,14) AS cada_ref, cleabs, mode_rattachement, badge_actif
FROM inventaire_general WHERE cleabs IS NULL ORDER BY ref LIMIT 3;

-- V5c — les cas desamb_serree (complexe sportif, ermitage) :
SELECT ref, left(deno,30) AS deno, cleabs, mode_rattachement
FROM inventaire_general WHERE desamb_serree;

-- V6 — liste blanche totale : deno_affichage vide, badge_actif partout true :
SELECT (SELECT count(*) FROM deno_affichage)          AS deno_affichage_rows,
       count(*) FILTER (WHERE badge_actif)            AS badge_actif_true,
       count(*)                                       AS total
FROM inventaire_general;
